import pytest
import requests

def test_submit_valid_timesheet_accepted(auth_fixture, clean_timesheet_week):
    token, employee_id, week_id = auth_fixture
    payload = {
        "employee_id": employee_id,
        "week_id": week_id,
        "days": {
            "mon": 8, "tue": 8, "wed": 8,
            "thu": 8, "fri": 8, "sat": 0, "sun": 0
        }
    }
    resp = requests.post(
        "<BASE_URL>/timesheets/submit",
        json=payload,
        headers={"Authorization": f"Bearer {token}"}
    )
    assert resp.status_code in (200, 201)
    body = resp.json()
    assert body.get("state") == "submitted"

