import pytest
import requests

def test_submit_timesheet_idempotent_on_retry(auth_fixture, clean_timesheet_week):
    token, employee_id, week_id = auth_fixture
    payload = {
        "employee_id": employee_id,
        "week_id": week_id,
        "days": {
            "mon": 8, "tue": 8, "wed": 8,
            "thu": 8, "fri": 8, "sat": 0, "sun": 0
        }
    }
    headers = {"Authorization": f"Bearer {token}"}
    url = "<BASE_URL>/timesheets/submit"
    resp1 = requests.post(url, json=payload, headers=headers)
    assert resp1.status_code in (200, 201)
    assert resp1.json().get("state") == "submitted"
    resp2 = requests.post(url, json=payload, headers=headers)
    assert resp2.status_code in (200, 201)
    assert resp2.json().get("state") == "submitted"
